WHERE 1 = 1
  AND e.user_id = #{userId}

    AND (
      e.task_prompt LIKE CONCAT('%', #{keyword}, '%')
      OR e.essay_text LIKE CONCAT('%', #{keyword}, '%')
      OR u.nickname LIKE CONCAT('%', #{keyword}, '%')
    )

  AND e.mode = #{mode}
  AND up.study_stage = #{studyStage}
  AND e.overall_score >= #{scoreMin}
  AND e.overall_score <= #{scoreMax}


      AND ef.id IS NOT NULL
      AND ef.id IS NULL




      AND d.status = 2
      AND (d.status IS NULL OR d.status != 2)


  AND e.created_at >= #{createdFrom}
  AND e.created_at <= #{createdTo}
